Greedy best‑fit insertion tries all assign slots, picks the one yielding the smallest positive marginal cost increase for each ship, and if none fits creates a new assign at the end.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx        int
		deltaCost  float64
		ok         bool
	}
	for j := range oris {
		best := candidate{idx: -1, deltaCost: 1e100, ok: false}
		for i := 0; i < dispatch.AssignsLen || i == dispatch.AssignsLen; i++ {
			if i >= MAXASSIGNS {
				break
			}
			oldCost := dispatch.Assigns[i].Cost
			id := total_ship + j
			added := dispatch.Assigns[i].AddShip(id, oris[j], dess[j])
			if added {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if delta < best.deltaCost {
						best.idx = i
						best.deltaCost = delta
						best.ok = true
					}
				}
				dispatch.Assigns[i].RemoveShip(id)
				dispatch.Assigns[i].GenRoute()
			}
		}
		if best.ok {
			dispatch.Assigns[best.idx].AddShip(total_ship+j, oris[j], dess[j])
			dispatch.Assigns[best.idx].GenRoute()
			if best.idx >= dispatch.AssignsLen {
				dispatch.AssignsLen = best.idx + 1
			}
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				i := dispatch.AssignsLen
				added := dispatch.Assigns[i].AddShip(total_ship+j, oris[j], dess[j])
				if added {
					dispatch.Assigns[i].GenRoute()
					if dispatch.Assigns[i].Cost >= 0 {
						dispatch.AssignsLen++
					} else {
						dispatch.Assigns[i].RemoveShip(total_ship + j)
						dispatch.Assigns[i].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

